// Processa entrada: identifica se veio do chatbot ou form
const source = $input.item.json.source || 'form';

if (source === 'chatbot') {
  // ===== DADOS DO CHATBOT =====
  const projeto_id = parseInt($input.item.json.projeto_id);
  const fase = parseInt($input.item.json.fase);
  const email = String($input.item.json.email_destino || '').trim();

  // Parse dos objetos JSON (podem vir como string ou objeto)
  let backlog_reqs = {};
  let backlog_metricas = {};

  try {
    backlog_reqs = typeof $input.item.json.backlog_reqs === 'string' 
      ? JSON.parse($input.item.json.backlog_reqs) 
      : ($input.item.json.backlog_reqs || {});
  } catch (e) {
    console.error('Erro ao parsear backlog_reqs:', e);
  }

  try {
    backlog_metricas = typeof $input.item.json.backlog_metricas === 'string'
      ? JSON.parse($input.item.json.backlog_metricas)
      : ($input.item.json.backlog_metricas || {});
  } catch (e) {
    console.error('Erro ao parsear backlog_metricas:', e);
  }

  // Mapeia projeto_id para nome do produto
  let produtoNome = 'Desconhecido';
  if (projeto_id === 487) produtoNome = 'Orbit';
  else if (projeto_id === 256) produtoNome = 'Wagtail';
  else if (projeto_id === 741) produtoNome = 'Auth';

  // Mapeia fase para nome
  const faseNome = fase === 1 ? 'Backlog' : 'Concluídos';

  return [{
    json: {
      projeto_id,
      fase,
      Email: email,
      backlog_reqs,
      backlog_metricas,
      source: 'chatbot',
      // Campos extras para compatibilidade com fluxo do form
      'Selecione o produto desejado': produtoNome,
      'Selecione a fase para análise': faseNome,
      nome: projeto_id === 487 ? 'Squad Assessment' : 
            projeto_id === 256 ? 'Squad Wagtail' : 
            projeto_id === 741 ? 'MVP Auth 2.0' : null,
      nome_completo: projeto_id === 487 ? 'Logbit - Squad Assessment' : 
                     projeto_id === 256 ? 'Logbit - Squad Wagtail' : 
                     projeto_id === 741 ? 'Logbit - MVP Auth 2.0' : null
    }
  }];

} else {
  return $input.all().map(item => {
    return {
      json: {
        ...item.json, // <-- Mantém todas as chaves e valores originais do form
        source: 'form' // <-- Adiciona explicitamente 'source: form' no JSON de saída
      }
    };
  });
}

